// 分享率
(maindata, torrent) => {
  const categoryList = ["不删"];
  const ruleData = [
    { progress: 0.4, ratio: 1.1 },
    { progress: 0.3, ratio: 0.8 },
    { progress: 0.2, ratio: 0.5 },
    { progress: 0.1, ratio: 0.3 },
    { progress: 0.05, ratio: 0.1 }
  ];
  const { state, upspeed, category, progress, ratio } = torrent.originProp;
  if (categoryList.indexOf(category) !== -1) {
    return false;
  }
   if (
    (moment().hour() >= 0 && moment().hour() <= 8)
  ) {
    return false;
  }
  for (const rule of ruleData) {
    if (
      state == "downloading" &&
      progress >= rule.progress &&
      ratio <= rule.ratio &&
      upspeed <= util.calSize(6, "MiB")
    ) {
      return true;
    }
  }
  return false;
};
